from flask import Flask, request, jsonify, redirect
from urllib.parse import urlparse
import uuid

app = Flask(__name__)

# Example registered client data
clients = {
    'client_id_123': {
        'client_secret': 'secret_123',
        'redirect_uris': [
            'https://example.com/callback',
            'https://staging.example.com/callback',
            'https://dev.example.com/callback'
        ]
    }
}

# In-memory storage for authorization codes
authorization_codes = {}

@app.route('/authorize', methods=['GET'])
def authorize():
    client_id = request.args.get('client_id')
    redirect_uri = request.args.get('redirect_uri')
    response_type = request.args.get('response_type')
    state = request.args.get('state')

    if client_id not in clients:
        return jsonify({'error': 'invalid_client'}), 400

    client = clients[client_id]
    if not any(redirect_uri.startswith(uri) for uri in client['redirect_uris']):
        return jsonify({'error': 'invalid_redirect_uri'}), 400

    if response_type != 'code':
        return jsonify({'error': 'unsupported_response_type'}), 400

    # Generate authorization code
    auth_code = str(uuid.uuid4())
    authorization_codes[auth_code] = {
        'client_id': client_id,
        'redirect_uri': redirect_uri
    }

    redirect_response = f"{redirect_uri}?code={auth_code}"
    if state:
        redirect_response += f"&state={state}"

    return redirect(redirect_response)

@app.route('/token', methods=['POST'])
def token():
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')
    code = request.form.get('code')
    redirect_uri = request.form.get('redirect_uri')
    grant_type = request.form.get('grant_type')

    if grant_type != 'authorization_code':
        return jsonify({'error': 'unsupported_grant_type'}), 400

    if client_id not in clients:
        return jsonify({'error': 'invalid_client'}), 400

    client = clients[client_id]
    if client['client_secret'] != client_secret:
        return jsonify({'error': 'invalid_client'}), 400

    if code not in authorization_codes:
        return jsonify({'error': 'invalid_grant'}), 400

    auth_data = authorization_codes.pop(code)
    if auth_data['client_id'] != client_id or auth_data['redirect_uri'] != redirect_uri:
        return jsonify({'error': 'invalid_grant'}), 400

    # Generate access token
    access_token = str(uuid.uuid4())

    return jsonify({
        'access_token': access_token,
        'token_type': 'Bearer'
    })

